import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

// Persistent AI client instance
const aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {

  const systemInstruction = `You are a world-class master philologist and polyglot specializing in ${sourceLanguage} and ${targetLanguage}.
Your task is to provide an exhaustive philological analysis following a STRICT SEMANTIC SEPARATION PROTOCOL.

### 🛠️ SEMANTIC SEPARATION PROTOCOL (STRICT)

1. **SYNONYMS (SOURCE DOMAIN - ${sourceLanguage} ONLY)**:
   - These must refer ONLY to the searched word "${query}".
   - They must be in the SAME language as the searched word (${sourceLanguage}).
   - Provide true synonyms or near-synonyms.
   - **PROHIBITION**: Never include translations or target language words here.

2. **SEMANTIC VARIATIONS (TARGET DOMAIN - ${targetLanguage} ONLY)**:
   - These must refer ONLY to the translated result in ${targetLanguage}.
   - They must be in the language of the translation (${targetLanguage}).
   - Provide contextual or descriptive variants (e.g., if searching "Non" -> "Brot", variations might be "Fladenbrot", "Vollkornbrot").
   - **PROHIBITION**: Never include the source word or its ${sourceLanguage} synonyms here.

3. **MAPPING RULES**:
   - ❌ Do NOT repeat the same word across both sections.
   - ❌ Do NOT translate the synonyms into ${targetLanguage}.
   - ❌ Do NOT invent variants if they don't exist.
   - Maintain a strict, impenetrable wall between the source and target linguistic domains.

**EXAMPLE**:
Search: "Non" (${sourceLanguage} -> ${targetLanguage})
Synonyms (strictly ${sourceLanguage}): ["Patir", "Obi non", "Yopgan non"]
Semantic Variations (strictly ${targetLanguage}): ["Frisches Brot", "Fladenbrot", "Trockenes Brot"]`;

  const prompt = `Linguistically analyze the ${sourceLanguage} term "${query}" and translate it into ${targetLanguage}. 
Provide the main translation, 3-5 synonyms in ${sourceLanguage}, and 3-5 semantic variations of the result in ${targetLanguage}.`;

  const response = await aiClient.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          lemma: { type: Type.STRING, description: `Canonical form in ${sourceLanguage}` },
          inflection: { type: Type.STRING, description: `Morphological description of query in ${sourceLanguage}` },
          mainTranslation: { type: Type.STRING, description: `The primary equivalent in ${targetLanguage}` },
          sourceLevel: { type: Type.STRING, description: "Estimated CEFR Level (A1-C2)" },
          philology: {
            type: Type.OBJECT,
            properties: {
              etymology: { type: Type.STRING, description: "Origin/History" },
              historicalNotes: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING, description: `Grammatical gender STICTLY in ${targetLanguage}` },
              plural: { type: Type.STRING, description: `Plural form STICTLY in ${targetLanguage}` }
            },
            required: ["etymology", "partOfSpeech"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              usage: { type: Type.STRING, description: `Usage explanation in ${targetLanguage}` },
              register: { type: Type.STRING, enum: ['formal', 'informal', 'neutral'] },
              notes: { type: Type.STRING, description: `Contextual notes in ${targetLanguage}` }
            },
            required: ["usage", "register", "notes"]
          },
          synonyms: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: `True synonyms of the searched term strictly in ${sourceLanguage} ONLY. NO TRANSLATIONS.`
          },
          variations: {
            type: Type.ARRAY,
            description: `Contextual or descriptive variants of the RESULT in ${targetLanguage}. STRICTLY NO ${sourceLanguage} WORDS.`,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: `Variant of the translation in ${targetLanguage}` },
                confidence: { type: Type.NUMBER },
                source: { type: Type.STRING, enum: ['ai'] }
              },
              required: ["text", "confidence", "source"]
            }
          },
          literature: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: `Quote in ${sourceLanguage}` },
                translation: { type: Type.STRING, description: `Translation of quote in ${targetLanguage}` },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: `Idiom in ${sourceLanguage}` },
                translation: { type: Type.STRING, description: `Equivalent in ${targetLanguage}` },
                explanation: { type: Type.STRING, description: `Context in ${targetLanguage}` },
                type: { type: Type.STRING, enum: ['greeting', 'proverb', 'historical', 'general'] }
              }
            }
          }
        },
        required: ["term", "lemma", "mainTranslation", "sourceLevel", "philology", "culture", "synonyms", "variations", "literature", "idioms"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: crypto.randomUUID(),
    term: rawData.term || query,
    lemma: rawData.lemma,
    inflection: rawData.inflection,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel,
    philology: rawData.philology,
    culture: rawData.culture,
    synonyms: rawData.synonyms || [],
    variations: rawData.variations || [],
    literature: rawData.literature || [],
    idioms: rawData.idioms || [],
    timestamp: Date.now()
  };
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const context = entries.map(e => `${e.term} -> ${e.mainTranslation} (${e.sourceLang} to ${e.targetLang})`).join(", ");

  const response = await aiClient.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a linguistic quiz based on these translations: ${context}. Create 2 multiple-choice questions for each word.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            correctAnswer: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            explanation: { type: Type.STRING }
          },
          required: ["question", "correctAnswer", "options", "explanation"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

// Persistent AI client instance
const aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function translateWord(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {

  const systemInstruction = `You are a world-class master philologist generating entries for a multilingual scholarly learner’s dictionary. 
Your tone is sophisticated, precise, and archival.

### HARD CONSTRAINTS (ABSOLUTE — MUST NOT BE VIOLATED):

1. **SECTION LANGUAGE LOCK**:
   - **Synonyms (${sourceLanguage})**: MUST be in ${sourceLanguage} ONLY.
   - **Semantic Variations (${targetLanguage})**: MUST be in ${targetLanguage} ONLY.
   - **Example**: If searching "Non" (${sourceLanguage}) -> "Brot" (${targetLanguage}):
     - Synonyms: ["Patir", "Obi non"] (Uzbek)
     - Variations: ["Frisches Brot", "Fladenbrot"] (German)
   - ❌ **PROHIBITION**: Never mix languages within these sections. Never include target words in synonyms. Never include source words in variations.

2. **SEMANTIC SCOPE LOCK**:
   - Synonyms = same concept as the searched word ("${query}").
   - Semantic Variations = variants/subtypes of the translated word, not the original.
   - ❌ Never repeat the searched word or its direct forms inside Semantic Variations.

3. **CONTENT RESTRICTIONS**:
   - ❌ No percentages (%) anywhere in the text.
   - ❌ No slashes (/) anywhere in the text.
   - ❌ Max 3 items per list (Synonyms, Variations, Idioms).
   - ❌ No academic paragraphs; use concise, archival phrasing.

4. **SELF-VALIDATION STEP**:
   - Before completing the response, verify: Are synonyms in ${sourceLanguage}? Are variations in ${targetLanguage}? Is the item count <= 3? Are there any slashes or percentages? 
   - If validation fails, regenerate.`;

  const prompt = `Linguistically analyze the ${sourceLanguage} term "${query}" and translate it into ${targetLanguage}. 
Adhere strictly to the Language-Locked Dictionary Protocol.`;

  const response = await aiClient.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      systemInstruction: systemInstruction,
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          lemma: { type: Type.STRING, description: `Canonical form in ${sourceLanguage}` },
          inflection: { type: Type.STRING, description: `Morphological description of query in ${sourceLanguage}` },
          mainTranslation: { type: Type.STRING, description: `The primary equivalent in ${targetLanguage}` },
          sourceLevel: { type: Type.STRING, description: "Estimated CEFR Level (A1-C2)" },
          philology: {
            type: Type.OBJECT,
            properties: {
              etymology: { type: Type.STRING, description: "Origin and History" },
              historicalNotes: { type: Type.STRING },
              partOfSpeech: { type: Type.STRING },
              gender: { type: Type.STRING, description: `Grammatical gender strictly in ${targetLanguage}` },
              plural: { type: Type.STRING, description: `Plural form strictly in ${targetLanguage}` }
            },
            required: ["etymology", "partOfSpeech"]
          },
          culture: {
            type: Type.OBJECT,
            properties: {
              usage: { type: Type.STRING, description: `Usage explanation in ${targetLanguage}` },
              register: { type: Type.STRING, enum: ['formal', 'informal', 'neutral'] },
              notes: { type: Type.STRING, description: `Contextual notes in ${targetLanguage}` }
            },
            required: ["usage", "register", "notes"]
          },
          synonyms: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            maxItems: 3,
            description: `Synonyms strictly in ${sourceLanguage}. No slashes.`
          },
          variations: {
            type: Type.ARRAY,
            maxItems: 3,
            description: `Semantic variations of the translation strictly in ${targetLanguage}. No source words. No slashes.`,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                source: { type: Type.STRING, enum: ['ai'] }
              },
              required: ["text", "source"]
            }
          },
          literature: {
            type: Type.ARRAY,
            maxItems: 2,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: `Quote in ${sourceLanguage}` },
                translation: { type: Type.STRING, description: `Translation of quote in ${targetLanguage}` },
                source: { type: Type.STRING },
                author: { type: Type.STRING }
              }
            }
          },
          idioms: {
            type: Type.ARRAY,
            maxItems: 3,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING, description: `Idiom in ${sourceLanguage}` },
                translation: { type: Type.STRING, description: `Equivalent in ${targetLanguage}` },
                explanation: { type: Type.STRING, description: `Context in ${targetLanguage}` },
                type: { type: Type.STRING, enum: ['greeting', 'proverb', 'historical', 'general'] }
              }
            }
          }
        },
        required: ["term", "lemma", "mainTranslation", "sourceLevel", "philology", "culture", "synonyms", "variations", "literature", "idioms"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: crypto.randomUUID(),
    term: rawData.term || query,
    lemma: rawData.lemma,
    inflection: rawData.inflection,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    sourceLevel: rawData.sourceLevel,
    philology: rawData.philology,
    culture: rawData.culture,
    synonyms: rawData.synonyms || [],
    variations: rawData.variations || [],
    literature: rawData.literature || [],
    idioms: rawData.idioms || [],
    timestamp: Date.now()
  };
}

