import React from 'react';
import { LexicalEntry } from '../types';
import { speak, resumeAudioContext } from '../services/tts';

interface Props {
  entry: LexicalEntry;
}

const ResultCard: React.FC<Props> = ({ entry }) => {
  const isInflected = entry.lemma && entry.lemma.toLowerCase() !== entry.term.toLowerCase();

  const handleSpeak = async (text: string, lang: any) => {
    await resumeAudioContext();
    speak(text, lang);
  };

  const renderPrimaryTranslation = () => {
    const isGermanNoun = entry.targetLang === 'German' && entry.philology.partOfSpeech.toLowerCase().includes('substantiv');

    if (isGermanNoun) {
      const genderStr = entry.philology.gender ? `${entry.philology.gender} ${entry.mainTranslation.toLowerCase()}` : entry.mainTranslation.toLowerCase();
      const pluralStr = entry.philology.plural ? `, ${entry.philology.plural}` : '';
      return (
        <h2 className="text-4xl md:text-6xl lg:text-7xl serif font-black tracking-tighter lowercase leading-tight text-[#7c1a1a]">
          {entry.mainTranslation}
          <span className="text-lg md:text-3xl lg:text-4xl font-normal text-stone-300 ml-3 italic">
            ({genderStr}{pluralStr})
          </span>
        </h2>
      );
    }

    return (
      <h2 className="text-4xl md:text-7xl serif font-black tracking-tighter lowercase leading-none text-[#7c1a1a]">
        {entry.mainTranslation}
      </h2>
    );
  };

  return (
    <div className="bg-white border border-stone-200 shadow-sm rounded-sm animate-in fade-in slide-in-from-bottom-4 duration-700 overflow-hidden relative">
      {/* Decorative Archival Folio Lines */}
      <div className="absolute top-0 left-0 w-full h-1 bg-[#7c1a1a]/10" />

      <div className="p-6 md:p-12 border-b border-stone-100">
        <div className="flex flex-col md:flex-row justify-between gap-6 md:gap-10">
          <div>
            <div className="flex items-center gap-4 mb-3">
              <h1 className="text-5xl md:text-8xl serif font-black tracking-tighter lowercase leading-none text-stone-900">
                {entry.term}
              </h1>
              <button 
                onClick={() => handleSpeak(entry.term, entry.sourceLang)} 
                className="text-stone-300 hover:text-[#7c1a1a] transition-all p-2 hover:bg-stone-50 rounded-full"
                title={`Pronounce in ${entry.sourceLang}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>
              </button>
            </div>

            <div className="flex flex-wrap items-center gap-3 mb-4">
              <span className="bg-stone-900 text-white text-[9px] md:text-[10px] px-3 py-1 font-black uppercase tracking-[0.2em] rounded-sm">
                {entry.philology.partOfSpeech}
              </span>
              {entry.sourceLevel && (
                <span className="bg-[#7c1a1a] text-white text-[9px] md:text-[10px] px-3 py-1 font-black uppercase tracking-[0.2em] rounded-sm">
                  {entry.sourceLevel}
                </span>
              )}
            </div>

            {isInflected && (
              <div className="flex items-center gap-2">
                <span className="text-[10px] uppercase tracking-widest text-stone-400 font-bold">Lemma:</span>
                <span className="text-xl serif italic text-[#7c1a1a] lowercase">{entry.lemma}</span>
                {entry.inflection && (
                  <span className="text-[9px] uppercase tracking-tighter bg-stone-100 text-stone-500 px-2 py-0.5 rounded-full font-bold ml-2">
                    {entry.inflection}
                  </span>
                )}
              </div>
            )}
          </div>

          <div className="md:text-right pt-6 md:pt-0 border-t md:border-t-0 border-stone-50">
            <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black block mb-4">Primary Translation ({entry.targetLang.substring(0,3)})</span>
            <div className="flex items-center md:justify-end gap-6">
              {renderPrimaryTranslation()}
              <button 
                onClick={() => handleSpeak(entry.mainTranslation, entry.targetLang)} 
                className="text-stone-200 hover:text-[#7c1a1a] transition-all p-2 hover:bg-stone-50 rounded-full"
                title={`Pronounce in ${entry.targetLang}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/></svg>
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="flex flex-col lg:grid lg:grid-cols-12">
        <div className="lg:col-span-7 p-6 md:p-12 space-y-12 order-2 lg:order-1 border-b lg:border-b-0 lg:border-r border-stone-100">
          <section>
            <h3 className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-8 flex items-center gap-3">
              <span className="w-4 md:w-6 h-[1px] bg-[#7c1a1a]"></span>
              📚 Literary Manifestations
            </h3>
            <div className="space-y-10">
              {entry.literature.map((lit, i) => (
                <div key={i} className="relative pl-6 md:pl-8 border-l border-stone-200">
                  <p className="text-xl md:text-2xl serif font-medium text-stone-900 mb-2 leading-relaxed italic">"{lit.text}"</p>
                  {lit.translation && <p className="text-base md:text-lg serif text-stone-500 mb-4">{lit.translation}</p>}
                  <div className="flex items-center gap-3 text-[9px] md:text-[10px] uppercase tracking-widest font-black text-stone-400">
                    <span className="text-stone-900">{lit.author || 'Anonymous'}</span>
                    <span className="text-stone-200">/</span>
                    <span className="text-[#7c1a1a]">{lit.source}</span>
                  </div>
                </div>
              ))}
            </div>
          </section>

          <section className="bg-stone-50/30 p-6 md:p-10 rounded-sm border border-stone-100">
            <h3 className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-8 flex items-center gap-3">
              <span className="w-4 md:w-6 h-[1px] bg-stone-300"></span>
              🔬 Philological Analysis
            </h3>
            <div className="space-y-8">
              <div>
                <span className="text-[9px] md:text-[10px] uppercase tracking-widest text-stone-400 font-bold block mb-2">Etymology</span>
                <p className="text-lg md:text-xl serif italic text-stone-700 leading-relaxed">{entry.philology.etymology}</p>
              </div>
              {entry.philology.historicalNotes && (
                <div>
                  <span className="text-[9px] md:text-[10px] uppercase tracking-widest text-stone-400 font-bold block mb-2">Historical Records</span>
                  <p className="text-sm md:text-base text-stone-600 leading-relaxed italic">{entry.philology.historicalNotes}</p>
                </div>
              )}
            </div>
          </section>
        </div>

        <div className="lg:col-span-5 bg-stone-50/20 p-6 md:p-12 space-y-12 order-1 lg:order-2">
          {entry.synonyms && entry.synonyms.length > 0 && (
            <section>
              <h3 className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] text-stone-400 font-black mb-6 flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-stone-300"></span>
                🔗 Synonyms ({entry.sourceLang.toUpperCase()})
              </h3>
              <div className="flex flex-col gap-3">
                {entry.synonyms.map((syn, i) => (
                  <div 
                    key={i} 
                    onClick={() => handleSpeak(syn, entry.sourceLang)}
                    className="bg-white border border-stone-200 px-5 py-3 rounded-sm text-lg md:text-xl serif italic text-stone-600 hover:border-[#7c1a1a]/40 hover:text-[#7c1a1a] transition-all cursor-pointer shadow-sm active:scale-95 flex items-center justify-between group"
                  >
                    <span>{syn}</span>
                    <svg className="opacity-0 group-hover:opacity-100 transition-opacity text-stone-300" xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/></svg>
                  </div>
                ))}
              </div>
            </section>
          )}

          <section>
            <h3 className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] text-[#7c1a1a] font-black mb-6 flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-[#7c1a1a]/40"></span>
              🔁 Semantic Variations ({entry.targetLang.toUpperCase()})
            </h3>
            <div className="grid grid-cols-1 gap-4">
              {entry.variations.map((v, i) => (
                <div 
                  key={i} 
                  onClick={() => handleSpeak(v.text, entry.targetLang)}
                  className="bg-white border border-stone-100 p-5 rounded-sm flex justify-between items-center group hover:border-[#7c1a1a]/20 hover:shadow-md transition-all cursor-pointer"
                >
                  <span className="text-xl md:text-2xl serif text-stone-900 lowercase tracking-tight font-medium">
                    {v.text}
                  </span>
                  <svg className="opacity-0 group-hover:opacity-100 transition-opacity text-[#7c1a1a]/40" xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
                </div>
              ))}
            </div>
          </section>

          <section>
            <h3 className="text-[10px] md:text-[11px] uppercase tracking-[0.4em] text-stone-900 font-black mb-8 flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-stone-900"></span>
              🗣 Fixed Expressions ({entry.sourceLang.substring(0,3)})
            </h3>
            <div className="space-y-6">
              {entry.idioms.map((idm, i) => (
                <div key={i} className="bg-white p-6 md:p-8 border border-stone-100 shadow-sm rounded-sm hover:shadow-lg transition-all group">
                  <p className="text-xl md:text-2xl serif font-black text-stone-900 mb-2 group-hover:text-[#7c1a1a] transition-colors">{idm.text}</p>
                  <p className="text-base md:text-lg serif italic text-[#7c1a1a] mb-4">{idm.translation}</p>
                  <div className="h-[1px] w-12 bg-stone-100 mb-4" />
                  <p className="text-xs md:text-sm text-stone-400 leading-relaxed font-medium italic">{idm.explanation}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
