  const isInflected = entry.lemma && entry.lemma.toLowerCase() !== entry.term.toLowerCase();

  const handleSpeak = async (text: string, lang: any) => {
    await resumeAudioContext();
    speak(text, lang);
  };

  const getTargetMeta = () => {
    if (entry.targetLang === 'German' && entry.philology.partOfSpeech.toLowerCase().includes('substantiv')) {
      const gender = entry.philology.gender ? `(${entry.philology.gender} ${entry.mainTranslation.toLowerCase()}, ` : '(';
      const plural = entry.philology.plural ? `${entry.philology.plural})` : ')';
      return gender + plural; // Removed slash manually if it was implied
    }
    return '';
  };

  return (
    <div className="bg-white border border-stone-200 shadow-sm rounded-sm animate-in fade-in slide-in-from-bottom-4 duration-700 overflow-hidden">
      <div className="p-6 md:p-12 border-b border-stone-100">
        <div className="flex flex-col md:flex-row justify-between gap-6 md:gap-10">
          <div>
            <div className="flex items-center gap-4 mb-4">
              <h1 className="text-5xl md:text-8xl serif font-black tracking-tighter lowercase leading-none text-stone-900">
                {entry.term}
